Definition if_minus_plus_dec :=
  <{
  {{True}}
  if (X <= Y) then
              {{ True /\ X <= Y }} ->>
              {{ Y - X + X = Y }}
    Z := Y - X
              {{ Z + X = Y }}
  else
              {{ True /\ ~(X <= Y) }} ->>
              {{ X + Z = X + Z }}
    Y := X + Z
              {{ Y = X + Z }}
  end
  {{ Y = X + Z}} }>.

