div_mod_outer_triple_valid.solution:
Definition div_mod_dec (a b : nat) : decorated :=
  <{
  {{ True }} ->>
  {{ 0 * b + a = a }}
    X := a
             {{ 0 * b + X = a }};
    Y := 0
             {{ Y * b + X = a }};
    while b <= X do
             {{ Y * b + X = a /\ b <= X }} ->>
             {{ (Y + 1) * b + (X - b) = a }}
      X := X - b
             {{ (Y + 1) * b + X = a }};
      Y := Y + 1
             {{ Y * b + X = a }}
    end
  {{ Y * b + X = a /\ ~(b <= X) }} ->>
  {{ Y * b + X = a /\ ~(b <= X) }} }>.

Theorem div_mod_outer_triple_valid : forall a b,
  outer_triple_valid (div_mod_dec a b).
Proof. verify. Qed.

slow_assignment.solution:
Example slow_assignment_dec (m : nat) : decorated :=
  <{
    {{ X = m }}
      Y := 0
                    {{ X = m /\ Y = 0 }} ->>
                    {{ X + Y = m }} ;
      while X <> 0 do
                    {{ X + Y = m /\ X <> 0 }} ->>
                    {{ (X - 1) + (Y + 1) = m }}
         X := X - 1
                    {{ X + (Y + 1) = m }} ;
         Y := Y + 1
                    {{ X + Y = m }}
      end
    {{ X + Y = m /\ ~(X <> 0) }} ->>
    {{ Y = m }}
  }>.

Theorem slow_assignment : forall m,
  outer_triple_valid (slow_assignment_dec m).
Proof. verify. Qed.

